parameters.jsCode:
const originalInput = $('Set - Prepare QA Context').item.json;
const current = $input.item.json;

let aiOutput =
  current.output ||
  current.text ||
  current.message ||
  current.content ||
  current.data ||
  current;

if (typeof aiOutput === 'string') {
  aiOutput = aiOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    aiOutput = JSON.parse(aiOutput);
  } catch (error) {
    aiOutput = {
      wf04_qa_tests: {
        unit_tests: [],
        integration_tests: [],
        api_tests: [],
        ui_tests: [],
        test_scenarios: [],
        acceptance_criteria_coverage: {
          covered: [],
          missing: ["Invalid JSON from AI"]
        },
        test_data_requirements: [],
        automation_recommendations: [],
        ready_for_ci_cd: false,
        human_validation_required: true
      }
    };
  }
}

const qa = aiOutput.wf04_qa_tests || aiOutput;
const hasCoverageIssue = qa.acceptance_criteria_coverage?.missing?.length > 0;
const readyForCiCd = Boolean(qa.ready_for_ci_cd) && !hasCoverageIssue;

return {
  json: {
    ...originalInput,
    wf04_qa_tests: {
      unit_tests: Array.isArray(qa.unit_tests) ? qa.unit_tests : [],
      integration_tests: Array.isArray(qa.integration_tests) ? qa.integration_tests : [],
      api_tests: Array.isArray(qa.api_tests) ? qa.api_tests : [],
      ui_tests: Array.isArray(qa.ui_tests) ? qa.ui_tests : [],
      test_scenarios: Array.isArray(qa.test_scenarios) ? qa.test_scenarios : [],
      acceptance_criteria_coverage: qa.acceptance_criteria_coverage || { covered: [], missing: [] },
      test_data_requirements: Array.isArray(qa.test_data_requirements) ? qa.test_data_requirements : [],
      automation_recommendations: Array.isArray(qa.automation_recommendations) ? qa.automation_recommendations : [],
      human_validation_required: true,
      ready_for_ci_cd: readyForCiCd
    }
  }
};
